  ('promotion-d1056197-moex-00052', 'promotion-d1056197', 'promotion-d1056197-moex-114-3082b5f1', 'sub-promotion-d1056197-02', NULL, 'single_choice', '關於訴願審議委員會之敘述，下列何者正確？', '["各機關辦理訴願事件，應設訴願審議委員會，組成人員以具有法制專長者為限", "訴願審議委員會委員，由本機關高級職員及遴聘社會公正人士、學者、專家擔任之；其中社會 公正人士、學者、專家人數不得少於三分之一", "訴願決定應經訴願審議委員會會議之決議，其決議以委員三分之二之出席，出席委員過半數之 同意行之", "訴願審議委員會主任委員或委員對於訴願事件有利害關係者，應自行迴避，不得參與審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "74c4580f828f", "answer_pdf_sha1": "52ed235f6cad", "source_family": "moex-gov-tw", "moex": {"exam_code": "114160", "c": "135", "s": "0406", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員升官等考試、114年關務人員升官等考試、114年交通事業郵政人員升資考試、114年交通事業港務人員升資考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
