  ('promotion-d1056197-moex-00060', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '假設商品X與Y為互補品且都合乎供給法則與需求法則。在其他條件不變下，當Y財的生產要 素價格上漲時，有關X財之敘述，下列何者正確？', '["均衡價格會上漲且人們對X財的支出金額會增加", "均衡價格會上漲且人們對X財的支出金額會減少", "均衡價格會下跌且人們對X財的支出金額會增加", "均衡價格會下跌且人們對X財的支出金額會減少"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL),
  ('promotion-d1056197-moex-00061', 'promotion-d1056197', 'promotion-d1056197-moex-112-d3ff7f6b', 'sub-promotion-d1056197-01', NULL, 'single_choice', '有關消費者預算線的斜率和無異曲線的斜率，下列敘述何者正確？', '["預算線的斜率為兩商品的相對價格，無異曲線的斜率為邊際替代率", "預算線的斜率為邊際替代率，無異曲線的斜率為兩商品的相對價格", "預算線的斜率和無異曲線的斜率皆為兩商品的相對價格", "預算線的斜率和無異曲線的斜率皆為邊際替代率 13550"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:14+00:00", "source_pdf_sha1": "5f8ef5676876", "answer_pdf_sha1": "6da727d55af5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "105", "s": "0906", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "僑務行政"}'::jsonb, NULL)
